// Per-model invocation config (spec fairness rule 1). Generated by Phase 0,
// human-reviewed, committed under bench/model-bench/configs/.
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { join } from 'node:path';
import { slugify } from './slug.mjs';

const REASONING_FIELDS = new Set(['inline_think', 'reasoning_content', 'none']);
const TOOL_SUPPORT = new Set(['native', 'json_imitation', 'none']);

export function defaultConfig(model, { reasoning = false } = {}) {
  return reasoning
    ? { model, temperature: 0.6, top_p: 0.95, max_tokens: 32768, system_prompt: null, reasoning_toggle: null, reasoning_field: 'inline_think', tool_support: 'none', probe: {} }
    : { model, temperature: 0, top_p: 1, max_tokens: 8192, system_prompt: null, reasoning_toggle: null, reasoning_field: 'none', tool_support: 'none', probe: {} };
}

export function validateConfig(cfg) {
  const problems = [];
  if (!cfg.model) problems.push('model is required');
  for (const k of ['temperature', 'top_p', 'max_tokens']) {
    if (typeof cfg[k] !== 'number') problems.push(`${k} must be a number`);
  }
  if (!REASONING_FIELDS.has(cfg.reasoning_field)) problems.push(`reasoning_field must be one of ${[...REASONING_FIELDS].join('|')}`);
  if (!TOOL_SUPPORT.has(cfg.tool_support)) problems.push(`tool_support must be one of ${[...TOOL_SUPPORT].join('|')}`);
  if (problems.length) throw new Error(`Invalid config for ${cfg.model ?? '<unknown>'}: ${problems.join('; ')}`);
  return cfg;
}

export function saveConfig(cfg, configsDir) {
  validateConfig(cfg);
  mkdirSync(configsDir, { recursive: true });
  writeFileSync(join(configsDir, `${slugify(cfg.model)}.json`), JSON.stringify(cfg, null, 2) + '\n');
}

export function loadConfig(model, configsDir) {
  return validateConfig(JSON.parse(readFileSync(join(configsDir, `${slugify(model)}.json`), 'utf8')));
}

// Spec rule 7. Greedy models: one deterministic run, then variance runs at 0.2.
export function samplingPlan(cfg, nRuns = 5) {
  const base = { top_p: cfg.top_p, max_tokens: cfg.max_tokens };
  if (cfg.temperature === 0) {
    return [{ temperature: 0, ...base }, ...Array.from({ length: nRuns - 1 }, () => ({ temperature: 0.2, ...base }))];
  }
  return Array.from({ length: nRuns }, () => ({ temperature: cfg.temperature, ...base }));
}
